// Droste "log grid" tile — a scalloped logarithmic grid (the source texture for the
// Print Gallery conformal warp; sampled at w=(1-i)*log(z)/2pi with wrap-around, as in
// mathvisuals.org/PrintGallery). Raw 8-bit luminance (256x286), base64; decoded
// synchronously via atob at runtime. Tiles x-period 1, y-period H/W.
export const GRID_TEX = {
	width: 256,
	height: 286,
	yPeriod: 1.116371,
	b64: "",
};

let _cache: Uint8Array | null = null;
export function decodeGridTex(): Uint8Array {
	if (_cache) return _cache;
	const bin = atob(GRID_TEX.b64);
	const out = new Uint8Array(bin.length);
	for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
	_cache = out;
	return out;
}
